scwin.f_cancel = function () {
  $c.data.undoRow($p, ds_oilUnitPrice, "Y");
};
scwin.ds_oilUnitPrice_onrowpositionchange = function (info) {
  var row = info.newRowIndex;
  if (ds_oilUnitPrice.getCellData(row, "fmsYn") == "Y") {
    gr_oilUnitPrice.setReadOnly("cell", row, 'selfTransYn', true); //자가운송여부
    gr_oilUnitPrice.setReadOnly("cell", row, 'qty', true); //수량
    gr_oilUnitPrice.setReadOnly("cell", row, 'bpClntNo', true); //운송거래처
  } else {
    gr_oilUnitPrice.setReadOnly("cell", row, 'selfTransYn', false); //자가운송여부
    gr_oilUnitPrice.setReadOnly("cell", row, 'qty', false); //수량
    gr_oilUnitPrice.setReadOnly("cell", row, 'bpClntNo', false); //운송거래처
    gr_oilUnitPrice.setCellInputType(row, "bpClntNo", {
      inputType: "textImage"
    });
  }
  if (ds_oilUnitPrice.getCellData(row, "slipNo") != "") {
    gr_oilUnitPrice.setReadOnly("cell", row, 'rmk', true); //적요
    gr_oilUnitPrice.setReadOnly("cell", row, 'slipDt', true); //전표일자
  } else {
    if (ds_oilUnitPrice.getCellData(row, "payClsCd") == "10") {
      gr_oilUnitPrice.setReadOnly("cell", row, 'rmk', false);
      gr_oilUnitPrice.setReadOnly("cell", row, 'slipDt', false);
    } else if (ds_oilUnitPrice.getCellData(row, "payClsCd") == "01") {
      gr_oilUnitPrice.setReadOnly("cell", row, 'rmk', true);
      gr_oilUnitPrice.setReadOnly("cell", row, 'slipDt', true);
    }
  }
};

