scwin.gr_oilUnitPrice_OnPopup = async function (row, colid, nowValue) {
  //for=gr_oilUnitPrice event=OnPopup 참조

  scwin.gridColid = colid;
  var rtnList = new Array();

  //주유소명
  if (colid == 'oilStatNm') {
    scwin.textImageClickEvFlag = true;
    var sOilStatNm = ds_oilUnitPrice.getCellData(row, 'oilStatNm');
    ds_oilUnitPrice.setCellData(row, 'oilOilStatNo', "");
    ds_oilUnitPrice.setCellData(row, 'oilStatNm', "");
    ds_oilUnitPrice.setCellData(row, 'preCoAfClsCd', "");
    ds_oilUnitPrice.setCellData(row, 'sellClntNo', "");
    ds_oilUnitPrice.setCellData(row, 'sellClntNm', "");
    rtnList = await pscommon.RcfGridOilStatPops("", sOilStatNm, 'NM', '전체', '전체', '전체');
    if (rtnList != null && rtnList[0] != "N/A") {
      ds_oilUnitPrice.setCellData(row, 'oilOilStatNo', rtnList[0]);
      ds_oilUnitPrice.setCellData(row, 'oilStatNm', rtnList[1]);
      if (rtnList[2] == "1") {
        ds_oilUnitPrice.setCellData(row, 'preCoAfClsCd', "01");
      } else if (rtnList[2] == "0") {
        ds_oilUnitPrice.setCellData(row, 'preCoAfClsCd', "02");
      }
      ds_oilUnitPrice.setCellData(row, 'sellClntNo', rtnList[3]);
      ds_oilUnitPrice.setCellData(row, 'sellClntNm', rtnList[4]);
    }
  }

  //매입거래처
  if (colid == 'selpchClntNo') {
    udc_part.setSelectId("retrieveClntEmpNoList"); //매입거래처코드
    await udc_part.cfCommonPopUp(scwin.udc_part_callBackFunc, ds_oilUnitPrice.getCellData(row, 'selpchClntNo'), "", 'T', null, null, null, null, null, null, null, null, null);
  }

  //운송거래처
  if (colid == 'bpClntNo') {
    udc_part.setSelectId("retrieveClntEmpNoList"); // 운송거래처코드
    await udc_part.cfCommonPopUp(scwin.udc_part_callBackFunc, ds_oilUnitPrice.getCellData(row, 'bpClntNo'), "", 'T', null, null, null, null, null, null, null, null, null);
  }

  //상품귀속부서(히든)
  if (colid == 'stockAcctDeptCd') {
    /*
    udc_part.setSelectId("retrieveAcctDeptCdInfo");												//상품귀속부서(재고귀속부서)코드
    await udc_part.cfCommonPopUp(scwin.udc_part_callBackFunc,ds_oilUnitPrice.getCellData(row,'stockAcctDeptCd'),"",'T',null,null,null,null,null,null,null,null,null);
    */
  }

  // 날짜 Or 정유사 Or 수량이 변경되는 경우 현물단가/금액 계산 로직 추가

  //거래구분
  var payClsCd = ds_oilUnitPrice.getCellData(row, 'payClsCd');

  //거래구분이 현물거래이고 그리드 컬럼이 입고일자, 매입 거래처, 리터일경우
  if (payClsCd == "10" && (colid == 'ioDt' || colid == 'selpchClntNo' || colid == 'qty')) {
    let bRtn = await scwin.f_calcAmt(row);
    /*
    if(!bRtn) {
        return false;
    }
    */
  }
  //거래구분이 여신거래이고 신규행인경우
  else if (payClsCd == "01" && ds_oilUnitPrice.getRowStatus(row) == "C") {
    // 신규 행 && 여신거래
    ds_oilUnitPrice.setCellData(row, "upr", "0");
    ds_oilUnitPrice.setCellData(row, "amt", "0");
  }
  return true;
};
scwin.udc_part_callBackFunc = async function (rtnList) {
  var row = ds_oilUnitPrice.getRowPosition();
  if (scwin.gridColid == 'selpchClntNo') {
    if (rtnList != null && rtnList[0] != "N/A") {
      ds_oilUnitPrice.setCellData(row, 'selpchClntNo', rtnList[0]);
      ds_oilUnitPrice.setCellData(row, 'selpchClntNm', rtnList[1]);
    }
  } else if (scwin.gridColid == 'bpClntNo') {
    if (rtnList != null && rtnList[0] != "N/A") {
      ds_oilUnitPrice.setCellData(row, 'bpClntNo', rtnList[0]);
      ds_oilUnitPrice.setCellData(row, 'bpClntNm', rtnList[1]);
    }
  } else if (scwin.gridColid == 'stockAcctDeptCd') {
    if (rtnList != null && rtnList[0] != "N/A") {
      ds_oilUnitPrice.setCellData(row, 'stockAcctDeptCd', rtnList[0]);
      ds_oilUnitPrice.setCellData(row, 'stockAcctDeptNm', rtnList[1]);
    }
  }
};
scwin.sleep = function (ms) {
  return new Promise(r => setTimeout(r, ms));
};
scwin.gr_oilUnitPrice_onafteredit = async function (rowIndex, columnIndex, value) {
  //for=gr_oilUnitPrice event=OnExit 참조
  var row = rowIndex;
  var rtnList = new Array();
  //주유소

  if (columnIndex == 2) {
    scwin.sleep(100).then(async function () {
      if (scwin.textImageClickEvFlag) {
        scwin.textImageClickEvFlag = false;
        return;
      } else {
        var sOilStatNm = ds_oilUnitPrice.getCellData(row, 'oilStatNm');
        ds_oilUnitPrice.setCellData(row, 'oilOilStatNo', "");
        ds_oilUnitPrice.setCellData(row, 'oilStatNm', "");
        ds_oilUnitPrice.setCellData(row, 'preCoAfClsCd', "");
        ds_oilUnitPrice.setCellData(row, 'sellClntNo', "");
        ds_oilUnitPrice.setCellData(row, 'sellClntNm', "");
        rtnList = await pscommon.RcfGridOilStatPop("", sOilStatNm, 'NM', '전체', '전체', '전체');
        if (rtnList != null && rtnList[0] != "N/A") {
          ds_oilUnitPrice.setCellData(row, 'oilOilStatNo', rtnList[0]);
          ds_oilUnitPrice.setCellData(row, 'oilStatNm', rtnList[1]);
          if (rtnList[2] == "1") {
            ds_oilUnitPrice.setCellData(row, 'preCoAfClsCd', "01");
          } else if (rtnList[2] == "0") {
            ds_oilUnitPrice.setCellData(row, 'preCoAfClsCd', "02");
          }
          ds_oilUnitPrice.setCellData(row, 'sellClntNo', rtnList[3]);
          ds_oilUnitPrice.setCellData(row, 'sellClntNm', rtnList[4]);
        }
      }
    });
  }

  //매입거래처코드
  if (columnIndex == 13) {
    scwin.gridColid = "selpchClntNo";
    udc_part.setSelectId("retrieveClntEmpNoList");
    await udc_part.cfCommonPopUp(scwin.udc_part_callBackFunc, ds_oilUnitPrice.getCellData(row, 'selpchClntNo'), "", 'T', null, null, null, null, null, null, null, null, null);
  }

  // 운송거래처코드
  if (columnIndex == 26 && ds_oilUnitPrice.getCellData(row, 'bpClntNo') != "") {
    scwin.gridColid = "bpClntNo";
    udc_part.setSelectId("retrieveClntEmpNoList");
    await udc_part.cfCommonPopUp(scwin.udc_part_callBackFunc, ds_oilUnitPrice.getCellData(row, 'bpClntNo'), "", 'T', null, null, null, null, null, null, null, null, null);
  }

  //상품귀속부서(재고귀속부서)코드 hidden 된 컬럼
  /*
  if(colid == 'stockAcctDeptCd'){														
  rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo',ds_oilUnitPrice.NameValue(row,'stockAcctDeptCd'),"",'T',null,null,null,null,null,null,null,null,null);
  if(rtnList !=null && rtnList[0]!= "N/A"){
  ds_oilUnitPrice.NameValue(row,'stockAcctDeptCd')=rtnList[0];
  ds_oilUnitPrice.NameValue(row, 'stockAcctDeptNm')=rtnList[1];
  }
  }
  */
  // 날짜 Or 정유사 Or 수량이 변경되는 경우 현물단가/금액 계산 로직 추가
  var payClsCd = ds_oilUnitPrice.getCellData(row, 'payClsCd');
  if (payClsCd == "10" && (columnIndex == 0 || columnIndex == 13 || columnIndex == 28)) {
    await scwin.f_calcAmt(row);
  } else if (payClsCd == "01" && ds_oilUnitPrice.getRowStatus(row) == "C") {
    // 신규 행 && 여신거래
    ds_oilUnitPrice.setCellData(row, "upr", 0);
    ds_oilUnitPrice.setCellData(row, "amt", 0);
  }
  return true;
};
scwin.gr_oilUnitPrice_oncellclick = async function (rowIndex, columnIndex, columnId) {
  var row = rowIndex;
  var colid = columnId;
  var RowStatus = ds_oilUnitPrice.getRowStatus(row);
  if (RowStatus == "R" || RowStatus == "D") {
    gr_oilUnitPrice.setReadOnly("cell", row, 'ioDt', true); //입고일자
    gr_oilUnitPrice.setReadOnly("cell", row, 'oilStatNm', true); //주유소명
    gr_oilUnitPrice.setReadOnly("cell", row, 'oilkndCd', true); //유종구분
    gr_oilUnitPrice.setReadOnly("cell", row, 'oilTskClsCd', true); //유류업무구분
    gr_oilUnitPrice.setReadOnly("cell", row, 'oilBizClsCd', true); //유류사업구분
    gr_oilUnitPrice.setReadOnly("cell", row, 'preCoAfClsCd', true); //판매구분
    gr_oilUnitPrice.setReadOnly("cell", row, 'selpchClsCd', true); //매출입구분
    gr_oilUnitPrice.setReadOnly("cell", row, 'selpchClntNo', true); //매입거래처
    gr_oilUnitPrice.setReadOnly("cell", row, 'sellClntNo', true); //매출거래처
    gr_oilUnitPrice.setReadOnly("cell", row, 'stockAcctDeptNm', true); //상품귀속부서
    gr_oilUnitPrice.setReadOnly("cell", row, 'homeClsCd', true); //소속구분코드
    gr_oilUnitPrice.setReadOnly("cell", row, 'stockAcctDeptCd', true); //상품귀속부서코드
    gr_oilUnitPrice.setReadOnly("cell", row, 'payClsCd', true); //거래구분

    if (ds_oilUnitPrice.getCellData(row, "fmsYn") == "Y") {
      gr_oilUnitPrice.setReadOnly("cell", row, 'selfTransYn', true); //자가운송여부
      gr_oilUnitPrice.setReadOnly("cell", row, 'qty', true); //수량
      gr_oilUnitPrice.setReadOnly("cell", row, 'bpClntNo', true); //운송거래처
    } else {
      gr_oilUnitPrice.setReadOnly("cell", row, 'selfTransYn', false); //자가운송여부
      gr_oilUnitPrice.setReadOnly("cell", row, 'qty', false); //수량
      gr_oilUnitPrice.setReadOnly("cell", row, 'bpClntNo', false); //운송거래처
      gr_oilUnitPrice.setCellInputType(row, "bpClntNo", {
        inputType: "textImage"
      });
    }
  }
  if (row > 0) {
    if (colid == "slipNo" && ds_oilUnitPrice.getCellData(row, "slipNo") != "") {
      let result = await $c.gus.cfShowSlipInfo($p, ds_oilUnitPrice.getCellData(row, "slipNo"));
    }
    var payClsCd = ds_oilUnitPrice.getCellData(row, 'payClsCd');
    if (payClsCd == "10" && colid == 'selfTransYn') {
      await scwin.f_calcAmt(row);
    }
  }
};

